import json
import psycopg2
import boto3
import logging
import os
from utility.archive import archive
import pandas as pd
from io import BytesIO
logger = logging.getLogger()
logger.setLevel(logging.INFO)
s3 = boto3.client("s3")
secman=boto3.client("secretsmanager")
secret_name=os.environ['SecretName']
def dataconnection(secret_name):
    try:
        response = secman.get_secret_value(SecretId=secret_name)
        secrets = json.loads(response['SecretString'])
        database = secrets['dbname']
        user=secrets['username']
        host=secrets['host']
        password=secrets['password']
        port=os.environ['Port']
        conn = psycopg2.connect(
        user=user,
        password=password,
        host=host,
        database=database,
        port=port)
        logger.info("Database connected")
        curr = conn.cursor()
        return conn, curr
    except Exception as e:
        logger.error(f"Couldn't connect to database")